#include<bits/stdc++.h>
using namespace std;
long long n,m,c;
bool vis[100010];
long long dis[100010];
vector<pair<long long,long long>> mp[100010];
void dijkstra(long long start)
{
	memset(vis,0,sizeof(vis));
	memset(dis,0x3f,sizeof(dis));
	dis[start]=0;
	priority_queue<pair<long long,long long>> q;
	q.push(make_pair(0,start));
	while(!q.empty())
	{
		long long t=q.top().second;
		q.pop();
		vis[t]=1;
		for(auto i:mp[t])
		{
			long long v=i.first,val=i.second;
			if(!vis[v]&&dis[v]>dis[t]+val)
			{
				dis[v]=dis[t]+val;
				q.push(make_pair(-dis[v],v));
			}
		}
	}
}
int main()
{
    scanf("%lld%lld%lld",&n,&m,&c);
    for(long long i=1;i<=m;i++)
    {
        long long u,v,w;
        scanf("%lld%lld%lld",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
    }
    for(long long i=0;i<=n;i++)
    {
        for(long long j=1;j<=n;j*=2)
        {
            if((i^j)<=n)
            {
                mp[i].push_back(make_pair((i^j),j*c));
            }
        }
    }
    long long s,t;
    scanf("%lld%lld",&s,&t);
    dijkstra(s);
    printf("%lld",dis[t]);
    return 0;
}
